import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a request to spin the Big Wheel.
 * Includes bet face (string: "1","2","5","10","20") and bet amount.
 */
export class WheelSpinComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(betFace: string, amount: number) {
        // sanitize
        const safeFace = String(betFace);
        const safeAmount = Math.max(1, Math.min(5000, Math.round(amount)));

        this._data = [safeFace, safeAmount];
        console.log('[🎡] Spin sent!', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        // no-op
    }
}
